import { Schema } from "effect"

// Branded IDs
export const TxHash = Schema.String.pipe(Schema.brand("@Falcon/TxHash"))
export type TxHash = Schema.Schema.Type<typeof TxHash>

export const ContractAddress = Schema.String.pipe(Schema.brand("@Falcon/ContractAddress"))
export type ContractAddress = Schema.Schema.Type<typeof ContractAddress>

// Domain types
export interface FalconKeypair {
  readonly secretKey: Uint8Array
  readonly verifyingKey: Uint8Array
  readonly publicKeyNtt: Int32Array // h polynomial, 512 coefficients
}

export interface FalconSignatureResult {
  readonly signature: Uint8Array
  readonly salt: Uint8Array
}

export interface PackedPublicKey {
  readonly slots: ReadonlyArray<string> // 29 hex strings (felt252)
}

export type VerificationStep =
  | { step: "idle" }
  | { step: "generating-keypair" }
  | { step: "signing" }
  | { step: "creating-hint" }
  | { step: "packing" }
  | { step: "verifying"; substep: string }
  | { step: "complete"; valid: boolean; durationMs: number }
  | { step: "error"; message: string }

export interface PipelineStep {
  readonly id: string
  readonly name: string
  readonly description: string
  readonly input: string
  readonly output: string
  readonly stepCount: number
  readonly status: "pending" | "active" | "complete"
}

import { Schema } from "effect"

export class WasmLoadError extends Schema.TaggedError<WasmLoadError>()(
  "WasmLoadError",
  { message: Schema.String },
) {}

export class KeygenError extends Schema.TaggedError<KeygenError>()(
  "KeygenError",
  { message: Schema.String },
) {}

export class SigningError extends Schema.TaggedError<SigningError>()(
  "SigningError",
  { message: Schema.String },
) {}

export class VerificationError extends Schema.TaggedError<VerificationError>()(
  "VerificationError",
  { message: Schema.String, step: Schema.String },
) {}

export class HintGenerationError extends Schema.TaggedError<HintGenerationError>()(
  "HintGenerationError",
  { message: Schema.String },
) {}

export class PackingError extends Schema.TaggedError<PackingError>()(
  "PackingError",
  { message: Schema.String },
) {}

export class StarknetRpcError extends Schema.TaggedError<StarknetRpcError>()(
  "StarknetRpcError",
  { message: Schema.String, code: Schema.Number },
) {}

export class AccountDeployError extends Schema.TaggedError<AccountDeployError>()(
  "AccountDeployError",
  { message: Schema.String, txHash: Schema.optional(Schema.String) },
) {}

export class InsufficientFundsError extends Schema.TaggedError<InsufficientFundsError>()(
  "InsufficientFundsError",
  { message: Schema.String, address: Schema.String, required: Schema.String },
) {}

/**
 * Tests for StarknetService — effect-services category.
 *
 * Strategy: StarknetService is tested via Layer.succeed mocks so no live
 * RPC connection is needed. This covers the contract (method signatures,
 * error types, Exit values) without hitting mainnet.
 *
 * Additionally, the real StarknetService is tested for computeDeployAddress
 * (pure computation — no network call) using ConfigProvider to inject the
 * RPC URL.
 *
 * Coverage requirements:
 * - Every service method must have at least one success and one failure test
 * - StarknetRpcError, AccountDeployError must be producible by the service
 */

import { describe, it, expect } from "bun:test"
import { Effect, Exit, Layer, ConfigProvider } from "effect"
import { StarknetService } from "../../services/StarknetService"
import { StarknetRpcError, AccountDeployError } from "../../services/errors"
import type { PackedPublicKey, TxHash, ContractAddress } from "../../services/types"

// ---------------------------------------------------------------------------
// Mock StarknetService helpers
// Use `as any` for mock service objects because test mocks intentionally
// include error-producing methods that differ from the inferred success-only types.
// ---------------------------------------------------------------------------

const mockAddress = "0x049d36570d4e46f48e99674bd3fcc84644ddd6b96f7c741b1562b82f9e004dc7" as ContractAddress
const mockTxHash = "0x7f3e2a1b9c4d5e6f" as TxHash

// Success mock: all methods return successful Effects
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const makeSuccessService = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    computeDeployAddress: (_pk: PackedPublicKey) =>
      Effect.succeed(mockAddress),
    getBalance: (_addr: string) => Effect.succeed(BigInt("1000000000000000000")),
    deployAccount: (_pk: PackedPublicKey, _sk: string) =>
      Effect.succeed({ txHash: mockTxHash, address: mockAddress }),
    waitForTx: (_tx: string) => Effect.succeed(undefined as void),
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    provider: {} as any,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } as any)

// Failing mock: all methods return failing Effects with typed errors
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const makeFailingService = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    computeDeployAddress: (_pk: PackedPublicKey) =>
      Effect.fail(new StarknetRpcError({ message: "mock rpc error", code: -1 })),
    getBalance: (_addr: string) =>
      Effect.fail(new StarknetRpcError({ message: "balance fetch failed", code: -32000 })),
    deployAccount: (_pk: PackedPublicKey, _sk: string) =>
      Effect.fail(new AccountDeployError({ message: "deploy rejected" })),
    waitForTx: (_tx: string) =>
      Effect.fail(new StarknetRpcError({ message: "tx timeout", code: -1 })),
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    provider: {} as any,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } as any)

/** Run an effect provided with a specific StarknetService mock layer */
async function runWith<A, E>(
  effect: Effect.Effect<A, E, StarknetService>,
  serviceLayer: Layer.Layer<StarknetService>,
): Promise<Exit.Exit<A, E>> {
  return Effect.runPromiseExit(
    effect.pipe(Effect.provide(serviceLayer)),
  )
}

// ---------------------------------------------------------------------------
// computeDeployAddress
// ---------------------------------------------------------------------------

describe("StarknetService.computeDeployAddress (mocked)", () => {
  const mockPk: PackedPublicKey = {
    slots: Array.from({ length: 29 }, (_, i) => `0x${i.toString(16).padStart(64, "0")}`),
  }

  it("succeeds and returns a ContractAddress string", async () => {
    const exit = await runWith(
      StarknetService.computeDeployAddress(mockPk),
      makeSuccessService(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(typeof exit.value).toBe("string")
      expect(exit.value.startsWith("0x")).toBe(true)
    }
  })

  it("fails with StarknetRpcError when service fails", async () => {
    const exit = await runWith(
      StarknetService.computeDeployAddress(mockPk),
      makeFailingService(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("StarknetRpcError")
    }
  })
})

// ---------------------------------------------------------------------------
// getBalance
// ---------------------------------------------------------------------------

describe("StarknetService.getBalance (mocked)", () => {
  it("succeeds and returns a bigint balance", async () => {
    const exit = await runWith(
      StarknetService.getBalance("0x1234"),
      makeSuccessService(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(typeof exit.value).toBe("bigint")
      expect(exit.value).toBe(BigInt("1000000000000000000"))
    }
  })

  it("fails with StarknetRpcError when RPC call fails", async () => {
    const exit = await runWith(
      StarknetService.getBalance("0xdeadbeef"),
      makeFailingService(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("StarknetRpcError")
    }
  })
})

// ---------------------------------------------------------------------------
// deployAccount
// ---------------------------------------------------------------------------

describe("StarknetService.deployAccount (mocked)", () => {
  const mockPk: PackedPublicKey = {
    slots: Array.from({ length: 29 }, (_, i) => `0x${i.toString(16).padStart(64, "0")}`),
  }

  it("succeeds and returns txHash and address", async () => {
    const exit = await runWith(
      StarknetService.deployAccount(mockPk, "0xprivkey"),
      makeSuccessService(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value.txHash).toBe(mockTxHash)
      expect(exit.value.address).toBe(mockAddress)
    }
  })

  it("fails with AccountDeployError when deployment is rejected", async () => {
    const exit = await runWith(
      StarknetService.deployAccount(mockPk, "0xprivkey"),
      makeFailingService(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("AccountDeployError")
    }
  })
})

// ---------------------------------------------------------------------------
// waitForTx
// ---------------------------------------------------------------------------

describe("StarknetService.waitForTx (mocked)", () => {
  it("succeeds (returns void) when transaction confirms", async () => {
    const exit = await runWith(
      StarknetService.waitForTx("0xabc123"),
      makeSuccessService(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
  })

  it("fails with StarknetRpcError when tx times out", async () => {
    const exit = await runWith(
      StarknetService.waitForTx("0xdeadbeef"),
      makeFailingService(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("StarknetRpcError")
    }
  })
})

// ---------------------------------------------------------------------------
// Real StarknetService: computeDeployAddress (pure computation, no network)
// ---------------------------------------------------------------------------

describe("StarknetService.computeDeployAddress (real implementation)", () => {
  const mockPk: PackedPublicKey = {
    slots: Array.from({ length: 29 }, (_, i) => `0x${i.toString(16).padStart(64, "0")}`),
  }

  const withTestConfig = ConfigProvider.fromMap(
    new Map([["NEXT_PUBLIC_STARKNET_RPC_URL", "http://localhost:9999"]]),
  )

  it("returns a hex string address (pure computation, no RPC call)", async () => {
    const exit = await Effect.runPromiseExit(
      StarknetService.computeDeployAddress(mockPk).pipe(
        Effect.provide(StarknetService.Default),
        Effect.provide(Layer.setConfigProvider(withTestConfig)),
      ),
    )
    // computeDeployAddress is pure (hash + CallData only), should succeed
    // even with a fake RPC URL because no network call is made
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(typeof exit.value).toBe("string")
    }
  })
})

// ---------------------------------------------------------------------------
// StarknetService: fails when Config is missing
// ---------------------------------------------------------------------------

describe("StarknetService: initialization failure", () => {
  it("StarknetService.Default fails gracefully when Config is missing", async () => {
    const exit = await Effect.runPromiseExit(
      StarknetService.computeDeployAddress({
        slots: Array.from({ length: 29 }, () => "0x0"),
      }).pipe(
        // Provide service without any ConfigProvider — should fail with
        // a config error (no NEXT_PUBLIC_STARKNET_RPC_URL set)
        Effect.provide(StarknetService.Default),
      ),
    )
    // Should fail because no config is provided
    expect(Exit.isFailure(exit)).toBe(true)
  })
})

/**
 * Tests for Starknet-specific Schema.TaggedError classes.
 *
 * Coverage requirements:
 * - Every Schema.TaggedError must be constructable and matchable
 * - _tag must equal the class name string
 * - Errors must roundtrip through Effect failure/exit
 */

import { describe, it, expect } from "bun:test"
import { Effect, Exit, Cause } from "effect"
import {
  StarknetRpcError,
  AccountDeployError,
  InsufficientFundsError,
} from "../../services/errors"

describe("StarknetRpcError", () => {
  it("is constructable with message and code", () => {
    const err = new StarknetRpcError({
      message: "RPC call failed",
      code: -32000,
    })
    expect(err.message).toBe("RPC call failed")
    expect(err.code).toBe(-32000)
    expect(err._tag).toBe("StarknetRpcError")
  })

  it("roundtrips through Effect.runPromiseExit", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(new StarknetRpcError({ message: "connection refused", code: -1 })),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    expect(Exit.isSuccess(exit)).toBe(false)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      expect(err._tag).toBe("Some")
      // @ts-expect-error — Option.Some wraps the error
      expect(err.value._tag).toBe("StarknetRpcError")
      // @ts-expect-error
      expect(err.value.code).toBe(-1)
    }
  })

  it("can be caught with catchTag", async () => {
    let caughtCode = 0
    await Effect.runPromise(
      Effect.fail(new StarknetRpcError({ message: "bad request", code: 400 })).pipe(
        Effect.catchTag("StarknetRpcError", (e) => {
          caughtCode = e.code
          return Effect.succeed(null)
        }),
      ),
    )
    expect(caughtCode).toBe(400)
  })

  it("_tag is 'StarknetRpcError' (not 'Error' or undefined)", () => {
    const err = new StarknetRpcError({ message: "x", code: 0 })
    expect(err._tag).toBe("StarknetRpcError")
    expect(err._tag).not.toBe("Error")
  })

  it("preserves code=0 (zero is valid, not falsy-filtered)", () => {
    const err = new StarknetRpcError({ message: "ok", code: 0 })
    expect(err.code).toBe(0)
  })
})

describe("AccountDeployError", () => {
  it("is constructable with message only (txHash optional)", () => {
    const err = new AccountDeployError({ message: "deploy failed" })
    expect(err.message).toBe("deploy failed")
    expect(err._tag).toBe("AccountDeployError")
    expect(err.txHash).toBeUndefined()
  })

  it("is constructable with message and txHash", () => {
    const err = new AccountDeployError({
      message: "tx reverted",
      txHash: "0xcafebeef",
    })
    expect(err.message).toBe("tx reverted")
    expect(err.txHash).toBe("0xcafebeef")
    expect(err._tag).toBe("AccountDeployError")
  })

  it("roundtrips through Effect.runPromiseExit", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(
        new AccountDeployError({ message: "nonce too low", txHash: "0xabc" }),
      ),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      // @ts-expect-error
      expect(err.value._tag).toBe("AccountDeployError")
      // @ts-expect-error
      expect(err.value.txHash).toBe("0xabc")
    }
  })

  it("can be caught with catchTag and txHash is accessible", async () => {
    let caughtHash: string | undefined = undefined
    await Effect.runPromise(
      Effect.fail(
        new AccountDeployError({ message: "failed", txHash: "0xdeadbeef" }),
      ).pipe(
        Effect.catchTag("AccountDeployError", (e) => {
          caughtHash = e.txHash
          return Effect.succeed(null)
        }),
      ),
    )
    expect(caughtHash!).toBe("0xdeadbeef")
  })

  it("succeeds in an effect chain when no error is thrown", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.succeed({ txHash: "0x123", address: "0xabc" }),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
  })
})

describe("InsufficientFundsError", () => {
  it("is constructable with message, address, and required", () => {
    const err = new InsufficientFundsError({
      message: "need more ETH",
      address: "0x1234",
      required: "1000000000000000000",
    })
    expect(err.message).toBe("need more ETH")
    expect(err.address).toBe("0x1234")
    expect(err.required).toBe("1000000000000000000")
    expect(err._tag).toBe("InsufficientFundsError")
  })

  it("roundtrips through Effect.runPromiseExit", async () => {
    const exit = await Effect.runPromiseExit(
      Effect.fail(
        new InsufficientFundsError({
          message: "balance too low",
          address: "0xbeef",
          required: "500",
        }),
      ),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      const err = Cause.failureOption(exit.cause)
      // @ts-expect-error
      expect(err.value._tag).toBe("InsufficientFundsError")
      // @ts-expect-error
      expect(err.value.address).toBe("0xbeef")
    }
  })

  it("can be caught with catchTag and address is accessible", async () => {
    let caughtAddress = ""
    await Effect.runPromise(
      Effect.fail(
        new InsufficientFundsError({
          message: "not enough",
          address: "0xfeed",
          required: "999",
        }),
      ).pipe(
        Effect.catchTag("InsufficientFundsError", (e) => {
          caughtAddress = e.address
          return Effect.succeed(null)
        }),
      ),
    )
    expect(caughtAddress).toBe("0xfeed")
  })

  it("is distinct from StarknetRpcError (different _tag)", () => {
    const rpcErr = new StarknetRpcError({ message: "x", code: 0 })
    const fundsErr = new InsufficientFundsError({
      message: "y",
      address: "0x0",
      required: "0",
    })
    expect(rpcErr._tag).not.toBe(fundsErr._tag)
    expect(fundsErr._tag).toBe("InsufficientFundsError")
  })
})

/**
 * Integration tests for Account Deploy Flow — account-deploy category.
 *
 * Tests the 5-step mainnet deployment flow:
 *   1. generating-keypair  (Falcon keygen via FalconService)
 *   2. packing             (pack public key to felt252 slots)
 *   3. computing-address   (pure hash + CallData computation)
 *   4. awaiting-funds      (balance check loop via getBalance)
 *   5. deploying           (broadcastAccount + waitForTx)
 *
 * Strategy:
 * - All StarknetService calls use Layer.succeed mocks — no live RPC
 * - Atoms are driven via Registry.make() for isolated state tracking
 * - An orchestrated Effect drives state transitions the same way
 *   AccountDeployFlow component will drive them in production
 * - Every service method has success + failure coverage
 * - Every Schema.TaggedError appears in at least one failure case
 *
 * Coverage requirements:
 * - computeDeployAddress: success, failure
 * - getBalance: success (funded), success (zero = awaiting funds), failure
 * - deployAccount: success, failure (no txHash), failure (with txHash)
 * - waitForTx: success, failure
 * - InsufficientFundsError: constructable, matchable, catchTag
 * - AccountDeployError: with/without txHash in deploy context
 * - Orchestrated flow: full happy-path, error propagation
 */

import { describe, it, expect, beforeEach } from "bun:test"
import { Effect, Exit, Layer, Option, Cause, ConfigProvider } from "effect"
import { Registry } from "@effect-atom/atom"

import { StarknetService } from "../../services/StarknetService"
import {
  StarknetRpcError,
  AccountDeployError,
  InsufficientFundsError,
} from "../../services/errors"
import type {
  PackedPublicKey,
  TxHash,
  ContractAddress,
} from "../../services/types"
import type { DeployStep } from "../../atoms/starknet"
import {
  deployStepAtom,
  deployedAddressAtom,
  deployTxHashAtom,
} from "../../atoms/starknet"

// ---------------------------------------------------------------------------
// Test fixtures
// ---------------------------------------------------------------------------

const MOCK_ADDRESS = "0x049d36570d4e46f48e99674bd3fcc84644ddd6b96f7c741b1562b82f9e004dc7" as ContractAddress
const MOCK_TX_HASH = "0x7f3e2a1b9c4d5e6f0a1b2c3d4e5f6a7b" as TxHash
const MOCK_PACKED_PK: PackedPublicKey = {
  slots: Array.from({ length: 29 }, (_, i) => `0x${i.toString(16).padStart(64, "0")}`),
}
const MOCK_PRIVATE_KEY = "0xdeadbeefcafebabe1234567890abcdef"
const FUNDED_BALANCE = BigInt("1000000000000000000") // 1 STRK
const ZERO_BALANCE = BigInt(0)

// ---------------------------------------------------------------------------
// Mock Layer builders
// ---------------------------------------------------------------------------

/**
 * Happy-path StarknetService: all methods succeed.
 */
const makeSuccessLayer = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    computeDeployAddress: (_pk: PackedPublicKey) =>
      Effect.succeed(MOCK_ADDRESS),
    getBalance: (_addr: string) =>
      Effect.succeed(FUNDED_BALANCE),
    deployAccount: (_pk: PackedPublicKey, _sk: string) =>
      Effect.succeed({ txHash: MOCK_TX_HASH, address: MOCK_ADDRESS }),
    waitForTx: (_tx: string) =>
      Effect.succeed(undefined as void),
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    provider: {} as any,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } as any)

/**
 * Zero-balance service: getBalance returns 0 (account not yet funded).
 */
const makeZeroBalanceLayer = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    computeDeployAddress: (_pk: PackedPublicKey) =>
      Effect.succeed(MOCK_ADDRESS),
    getBalance: (_addr: string) =>
      Effect.succeed(ZERO_BALANCE),
    deployAccount: (_pk: PackedPublicKey, _sk: string) =>
      Effect.fail(new AccountDeployError({ message: "should not be reached" })),
    waitForTx: (_tx: string) =>
      Effect.succeed(undefined as void),
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    provider: {} as any,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } as any)

/**
 * Deploy failure: deployAccount fails without txHash.
 */
const makeDeployFailureLayer = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    computeDeployAddress: (_pk: PackedPublicKey) =>
      Effect.succeed(MOCK_ADDRESS),
    getBalance: (_addr: string) =>
      Effect.succeed(FUNDED_BALANCE),
    deployAccount: (_pk: PackedPublicKey, _sk: string) =>
      Effect.fail(new AccountDeployError({ message: "insufficient fee" })),
    waitForTx: (_tx: string) =>
      Effect.succeed(undefined as void),
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    provider: {} as any,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } as any)

/**
 * Deploy failure: deployAccount fails WITH a txHash (tx was broadcast but reverted).
 */
const makeDeployRevertedLayer = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    computeDeployAddress: (_pk: PackedPublicKey) =>
      Effect.succeed(MOCK_ADDRESS),
    getBalance: (_addr: string) =>
      Effect.succeed(FUNDED_BALANCE),
    deployAccount: (_pk: PackedPublicKey, _sk: string) =>
      Effect.fail(
        new AccountDeployError({
          message: "transaction reverted",
          txHash: MOCK_TX_HASH,
        }),
      ),
    waitForTx: (_tx: string) =>
      Effect.succeed(undefined as void),
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    provider: {} as any,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } as any)

/**
 * RPC failure: computeDeployAddress fails (simulates RPC down at address computation).
 */
const makeRpcFailureLayer = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    computeDeployAddress: (_pk: PackedPublicKey) =>
      Effect.fail(new StarknetRpcError({ message: "connection refused", code: -1 })),
    getBalance: (_addr: string) =>
      Effect.fail(new StarknetRpcError({ message: "connection refused", code: -1 })),
    deployAccount: (_pk: PackedPublicKey, _sk: string) =>
      Effect.fail(new AccountDeployError({ message: "connection refused" })),
    waitForTx: (_tx: string) =>
      Effect.fail(new StarknetRpcError({ message: "timeout", code: -32003 })),
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    provider: {} as any,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } as any)

/** Run an effect provided with a specific StarknetService mock layer */
async function runWith<A, E>(
  effect: Effect.Effect<A, E, StarknetService>,
  serviceLayer: Layer.Layer<StarknetService>,
): Promise<Exit.Exit<A, E>> {
  return Effect.runPromiseExit(effect.pipe(Effect.provide(serviceLayer)))
}

// ---------------------------------------------------------------------------
// Group 1: DeployStep state machine — atom transitions
// (Complements atoms.test.ts; tests account-deploy-specific scenarios)
// ---------------------------------------------------------------------------

describe("DeployStep state machine — account-deploy scenarios", () => {
  it("idle → awaiting-funds preserves address in step payload", () => {
    const registry = Registry.make()
    registry.set(deployStepAtom, { step: "awaiting-funds", address: MOCK_ADDRESS })
    const state = registry.get(deployStepAtom)
    expect(state.step).toBe("awaiting-funds")
    expect((state as Extract<DeployStep, { step: "awaiting-funds" }>).address).toBe(MOCK_ADDRESS)
  })

  it("deploying step preserves address", () => {
    const registry = Registry.make()
    registry.set(deployStepAtom, { step: "deploying", address: MOCK_ADDRESS })
    const state = registry.get(deployStepAtom)
    expect(state.step).toBe("deploying")
    expect((state as Extract<DeployStep, { step: "deploying" }>).address).toBe(MOCK_ADDRESS)
  })

  it("deployed step carries both address and txHash", () => {
    const registry = Registry.make()
    registry.set(deployStepAtom, {
      step: "deployed",
      address: MOCK_ADDRESS,
      txHash: MOCK_TX_HASH,
    })
    const state = registry.get(deployStepAtom) as Extract<DeployStep, { step: "deployed" }>
    expect(state.step).toBe("deployed")
    expect(state.address).toBe(MOCK_ADDRESS)
    expect(state.txHash).toBe(MOCK_TX_HASH)
  })

  it("error step carries human-readable message", () => {
    const registry = Registry.make()
    registry.set(deployStepAtom, {
      step: "error",
      message: "Insufficient STRK balance — please fund the account",
    })
    const state = registry.get(deployStepAtom) as Extract<DeployStep, { step: "error" }>
    expect(state.step).toBe("error")
    expect(state.message).toContain("Insufficient")
  })

  it("subscribe fires on each deploy step transition", () => {
    const registry = Registry.make()
    const steps: string[] = []
    registry.subscribe(deployStepAtom, (v) => steps.push(v.step))
    registry.set(deployStepAtom, { step: "generating-keypair" })
    registry.set(deployStepAtom, { step: "packing" })
    registry.set(deployStepAtom, { step: "computing-address" })
    expect(steps).toEqual(["generating-keypair", "packing", "computing-address"])
  })

  it("deployedAddressAtom and deployTxHashAtom are set at deployed step", () => {
    const registry = Registry.make()
    // Simulate what AccountDeployFlow component will do on success
    registry.set(deployStepAtom, {
      step: "deployed",
      address: MOCK_ADDRESS,
      txHash: MOCK_TX_HASH,
    })
    registry.set(deployedAddressAtom, Option.some(MOCK_ADDRESS))
    registry.set(deployTxHashAtom, Option.some(MOCK_TX_HASH))

    expect(Option.isSome(registry.get(deployedAddressAtom))).toBe(true)
    expect(Option.isSome(registry.get(deployTxHashAtom))).toBe(true)
    expect(Option.getOrThrow(registry.get(deployedAddressAtom))).toBe(MOCK_ADDRESS)
    expect(Option.getOrThrow(registry.get(deployTxHashAtom))).toBe(MOCK_TX_HASH)
  })

  it("error resets deployedAddressAtom and deployTxHashAtom to none", () => {
    const registry = Registry.make()
    // Simulate a re-run after error: clear previous deployment state
    registry.set(deployedAddressAtom, Option.none())
    registry.set(deployTxHashAtom, Option.none())
    registry.set(deployStepAtom, { step: "error", message: "retry" })

    expect(Option.isNone(registry.get(deployedAddressAtom))).toBe(true)
    expect(Option.isNone(registry.get(deployTxHashAtom))).toBe(true)
  })
})

